func logRequest(r *http.Request) {
	uri := r.RequestURI
	method := r.Method
	fmt.Println("Got request!", method, uri)
}

// getDBConnection creates a new database connection using DATABASE_URL environment variable
func getDBConnection() (*sql.DB, error) {
	dbURL := os.Getenv("DATABASE_URL")
	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		return nil, fmt.Errorf("error connecting to database: %v", err)
	}

	// Set connection pool settings
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(25)
	db.SetConnMaxLifetime(5 * time.Minute)

	// Test the connection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return nil, fmt.Errorf("error pinging database: %v", err)
	}

	return db, nil
}

func main() {
	if os.Getenv("FORCE_PANIC") != "" {
		log.Println("panicking")
		panic("hello")
	}

	if strings.EqualFold(os.Getenv("ENABLE_MIGRATE"), "true") {
		log.Println("ENABLE_MIGRATE is true, running migrations...")
		db, err := getDBConnection()
		if err != nil {
			log.Fatalf("migration: failed to connect to database: %v", err)
		}
		_, err = db.Exec(`CREATE TABLE IF NOT EXISTS kv (key TEXT NOT NULL, value TEXT NOT NULL)`)
		if err != nil {
			db.Close()
			log.Fatalf("migration: failed to create kv table: %v", err)
		}
		log.Println("migration: kv table ready")
		db.Close()
	}

	if strings.EqualFold(os.Getenv("CHECK_CRASH"), "true") {
		log.Println("CHECK_CRASH is true, checking crash flag...")
		db, err := getDBConnection()
		if err != nil {
			log.Fatalf("check_crash: failed to connect to database: %v", err)
		}
		var value string
		err = db.QueryRow(`SELECT value FROM kv WHERE key = 'crash'`).Scan(&value)
		db.Close()
		if err == nil && strings.EqualFold(value, "true") {
			panic("crash flag is set to true in kv table")
		}
		if err != nil && err != sql.ErrNoRows {
			log.Printf("check_crash: error querying kv table: %v", err)
		}
	}

	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)
		fmt.Fprintf(w, "Hello! you've requested %s\n", r.URL.Path)
	})

	http.HandleFunc("/cached", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)
		maxAgeParams, ok := r.URL.Query()["max-age"]
		if ok && len(maxAgeParams) > 0 {
			maxAge, _ := strconv.Atoi(maxAgeParams[0])
			w.Header().Set("Cache-Control", fmt.Sprintf("max-age=%d", maxAge))
		}
		responseHeaderParams, ok := r.URL.Query()["headers"]
		if ok {
			for _, header := range responseHeaderParams {
				h := strings.Split(header, ":")
				w.Header().Set(h[0], strings.TrimSpace(h[1]))
			}
		}
		statusCodeParams, ok := r.URL.Query()["status"]
		if ok {
			statusCode, _ := strconv.Atoi(statusCodeParams[0])
			w.WriteHeader(statusCode)
		}
		requestID := uuid.Must(uuid.NewV4())
		fmt.Fprint(w, requestID.String())
	})

	http.HandleFunc("/headers", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)
		keys, ok := r.URL.Query()["key"]
		if ok && len(keys) > 0 {
			fmt.Fprint(w, r.Header.Get(keys[0]))
			return
		}
		headers := []string{}
		headers = append(headers, fmt.Sprintf("host=%s", r.Host))
		for key, values := range r.Header {
			headers = append(headers, fmt.Sprintf("%s=%s", key, strings.Join(values, ",")))
		}
		fmt.Fprint(w, strings.Join(headers, "\n"))
	})

	http.HandleFunc("/env", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)
		keys, ok := r.URL.Query()["key"]
		if ok && len(keys) > 0 {
			fmt.Fprint(w, os.Getenv(keys[0]))
			return
		}
		envs := []string{}
		envs = append(envs, os.Environ()...)
		fmt.Fprint(w, strings.Join(envs, "\n"))
	})

	http.HandleFunc("/status", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)
		codeParams, ok := r.URL.Query()["code"]
		if ok && len(codeParams) > 0 {
			statusCode, _ := strconv.Atoi(codeParams[0])
			if statusCode >= 200 && statusCode < 600 {
				w.WriteHeader(statusCode)
			}
		}
		requestID := uuid.Must(uuid.NewV4())
		fmt.Fprint(w, requestID.String())
	})

	http.HandleFunc("/panic", func(w http.ResponseWriter, r *http.Request) {
		panic("/panic called")
	})

	http.HandleFunc("/exit", func(w http.ResponseWriter, r *http.Request) {
		codeStr := r.URL.Query().Get("code")

		if codeStr == "" {
			http.Error(w, "missing 'code' query parameter", http.StatusBadRequest)
			return
		}

		code, err := strconv.Atoi(codeStr)
		if err != nil {
			http.Error(w, "invalid 'code' query parameter", http.StatusBadRequest)
			return
		}

		// Optional: write response before exiting
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("Exiting with code " + codeStr))

		// Important: ensure response is flushed before exit (best effort)
		if f, ok := w.(http.Flusher); ok {
			f.Flush()
		}

		os.Exit(code)
	})

	port := os.Getenv("PORT")
	if port == "" {
		port = "80"
	}

	for _, encodedRoute := range strings.Split(os.Getenv("ROUTES"), ",") {
		if encodedRoute == "" {
			continue
		}
		pathAndBody := strings.SplitN(encodedRoute, "=", 2)
		path, body := pathAndBody[0], pathAndBody[1]
		http.HandleFunc("/"+path, func(w http.ResponseWriter, r *http.Request) {
			fmt.Fprint(w, body)
		})
	}

	bindAddr := fmt.Sprintf(":%s", port)
	lines := strings.Split(startupMessage, "\n")
	fmt.Println()
	for _, line := range lines {
		fmt.Println(line)
	}
	fmt.Println()
	// Add database health check endpoint
	http.HandleFunc("/db-health", func(w http.ResponseWriter, r *http.Request) {
		logRequest(r)

		db, err := getDBConnection()
		if err != nil {
			http.Error(w, fmt.Sprintf("Database connection error: %v", err), http.StatusServiceUnavailable)
			return
		}
		defer db.Close()

		// Execute a simple query to verify the connection
		var result int
		err = db.QueryRow("SELECT 1").Scan(&result)
		if err != nil {
			http.Error(w, fmt.Sprintf("Database query error: %v", err), http.StatusServiceUnavailable)
			return
		}

		if result != 1 {
			http.Error(w, "Unexpected query result", http.StatusInternalServerError)
			return
		}

		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, "Database connection successful!\n")
	})

	fmt.Printf("==> Server listening at %s 🚀\n", bindAddr)

	err := http.ListenAndServe(fmt.Sprintf(":%s", port), nil)
	if err != nil {
		panic(err)
	}
}
